"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeClassify — the highest-frequency Finance write surface.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Finance/
   magellan-finance-classify.html

   The batch triage table (§14):
   - header select-all + per-row navy square checkboxes
   - per-row status DOT (ok green / review amber — never a verdict pill)
   - merchant + entity-link sub-line, amount, inline category selector (menu),
     confidence %, receipt chip, "+ Always merchant → category" rule chip
   - a pinned bulk bar (selected count + quiet bulk-accept)
   - a live batch consequence read computed ONLY from checked rows (§5)
   - commit states the exact count and shows the done state
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  CLASSIFY_CATEGORIES,
  CLASSIFY_ENTITY_LINKS,
  CLASSIFY_TRANSACTIONS,
  CLASSIFY_SUMMARY_META,
  categoryColor,
  receiptState,
  type ClassifyTransaction,
  type ReceiptState,
} from "@/features/finance/api/finance-classify-data";
import "./BridgeClassify.css";

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;
const fmtUSDShort = (v: number) => {
  const abs = Math.abs(v);
  if (abs >= 1_000_000) return `$${(abs / 1_000_000).toFixed(2).replace(/\.?0+$/, "")}M`;
  if (abs >= 1000) return `$${(abs / 1000).toFixed(1).replace(/\.0$/, "")}K`;
  return `$${Math.round(abs)}`;
};

/* Live, editable per-row state layered over the static demo data. */
interface RowState {
  category: string;
  checked: boolean;
  ruled: boolean;
}

export function BridgeClassify() {
  const { setPage } = useBridge();

  // One row-state per transaction; ok-confidence rows start pre-checked (§7).
  const [rows, setRows] = useState<RowState[]>(() =>
    CLASSIFY_TRANSACTIONS.map((t) => ({
      category: t.category,
      checked: t.conf === "ok",
      ruled: false,
    })),
  );
  const [openMenu, setOpenMenu] = useState<number | null>(null);
  const [committed, setCommitted] = useState(false);

  // Close the open category menu on any outside click (template parity).
  useEffect(() => {
    if (openMenu === null) return;
    const close = () => setOpenMenu(null);
    document.addEventListener("click", close);
    return () => document.removeEventListener("click", close);
  }, [openMenu]);

  const setCategory = (i: number, category: string) =>
    setRows((rs) =>
      rs.map((r, idx) => (idx === i ? { ...r, category, checked: true } : r)),
    );
  const toggleRow = (i: number, checked: boolean) =>
    setRows((rs) => rs.map((r, idx) => (idx === i ? { ...r, checked } : r)));
  const setRule = (i: number) =>
    setRows((rs) => rs.map((r, idx) => (idx === i ? { ...r, ruled: true } : r)));

  // Only rows that carry a category can be checked / bulk-accepted.
  const categorizedCount = rows.filter((r) => r.category).length;
  const allCheckable = rows.every((r, i) =>
    r.category ? r.checked : true,
  );

  const selectAll = (checked: boolean) =>
    setRows((rs) => rs.map((r) => (r.category ? { ...r, checked } : r)));
  const bulkAccept = () =>
    setRows((rs) => rs.map((r) => (r.category ? { ...r, checked: true } : r)));

  /* ─── The live batch consequence read — checked rows only (§5/§7) ─── */
  const read = useMemo(() => {
    const tx = CLASSIFY_TRANSACTIONS;
    const selected = rows
      .map((r, i) => ({ r, t: tx[i] }))
      .filter(({ r }) => r.checked && r.category);
    const classified = rows.filter((r) => r.category);
    const needCat = rows.filter((r) => !r.category);

    // Sum into buckets by category, from checked+categorized rows.
    const buckets: Record<string, number> = {};
    let selectedTotal = 0;
    for (const { r, t } of selected) {
      buckets[r.category] = (buckets[r.category] ?? 0) + t.amount;
      selectedTotal += t.amount;
    }
    const bucketNames = Object.keys(buckets);
    const largest = bucketNames.sort((a, b) => buckets[b] - buckets[a])[0];

    const totalValue = tx.reduce((a, t) => a + t.amount, 0);
    const autoMatched = tx.filter((t) => t.conf === "ok").length;
    const rulesCreated = rows.filter((r) => r.ruled).length;

    return {
      selectedCount: selected.length,
      selectedTotal,
      classifiedCount: classified.length,
      needCatCount: needCat.length,
      total: tx.length,
      bucketCount: bucketNames.length,
      largest: largest ? `${largest} ${fmtUSDShort(buckets[largest])}` : "—",
      autoMatched,
      totalValue,
      rulesCreated,
    };
  }, [rows]);

  const commit = () => {
    setCommitted(true);
    setTimeout(() => {
      setCommitted(false);
      setPage("home");
    }, 1800);
  };

  const receiptLabel = (state: ReceiptState) =>
    state === "attached" ? "receipt" : state === "auto" ? "auto" : "no receipt";

  const entityLink = (t: ClassifyTransaction) =>
    t.merchant ? (CLASSIFY_ENTITY_LINKS[t.merchant] ?? "") : "";

  return (
    <div className="bridge-content">
      {/* Page header */}
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M3 7 h18 M3 12 h18 M3 17 h11" />
            <path d="M17 15 l2 2 l3 -3.5" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Classify Transactions</div>
          <div className="bridge-page-head-sub">
            Magellan reads each transaction and proposes a category &mdash; you confirm or correct, then classify the batch. Keeps cost categories and CM1 honest.
          </div>
        </div>
      </div>

      {/* Summary bar */}
      <div className="bridge-rb-sku">
        <div className="bridge-rb-sku-main">
          <div className="bridge-rb-sku-name">{read.total} transactions to classify</div>
          <div className="bridge-rb-sku-meta">{CLASSIFY_SUMMARY_META}</div>
        </div>
        <div className="bridge-rb-sku-stats">
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{read.autoMatched}</span>
            <span className="bridge-rb-stat-k">auto-matched</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v" style={{ color: "#c79320" }}>
              {read.needCatCount}
            </span>
            <span className="bridge-rb-stat-k">need review</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{fmtUSD(read.totalValue)}</span>
            <span className="bridge-rb-stat-k">total value</span>
          </div>
        </div>
      </div>

      {/* The batch table */}
      <div className="bridge-ni-card bridge-cl-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">Review &amp; classify</span>
          <span className="bridge-ni-source manual">&#10022; Magellan proposed &mdash; change any category</span>
        </div>
        <table className="bridge-cl-table">
          <thead>
            <tr>
              <th className="bridge-cl-chk">
                <input
                  type="checkbox"
                  className="bridge-cl-checkbox"
                  aria-label="Select all classified rows"
                  checked={categorizedCount > 0 && allCheckable}
                  disabled={categorizedCount === 0}
                  onChange={(e) => selectAll(e.target.checked)}
                />
              </th>
              <th>Transaction</th>
              <th className="bridge-cl-amt-h">Amount</th>
              <th>Magellan&rsquo;s category</th>
              <th className="bridge-cl-st-h">Status</th>
            </tr>
          </thead>
          <tbody>
            {CLASSIFY_TRANSACTIONS.map((t, i) => {
              const r = rows[i];
              const link = entityLink(t);
              const receipt = receiptState({ ...t, category: r.category });
              const flagSet = r.category;
              const statusTone = t.conf === "ok" || flagSet ? "ok" : "review";
              const flagLabel = t.conf === "ok" ? "matched" : flagSet ? "set" : "review";
              const canRule = r.category && t.merchant;
              return (
                <tr key={t.source} className={`bridge-cl-row${r.checked && r.category ? " done" : ""}`}>
                  <td className="bridge-cl-chk">
                    <input
                      type="checkbox"
                      className="bridge-cl-checkbox"
                      aria-label={`Select ${t.desc}`}
                      checked={r.checked}
                      disabled={!r.category}
                      onChange={(e) => toggleRow(i, e.target.checked)}
                    />
                  </td>
                  <td>
                    <div className="bridge-cl-desc">{t.desc}</div>
                    <div className="bridge-cl-sub">
                      {t.source}
                      {link && (
                        <>
                          {" "}
                          <span className="bridge-cl-link">&middot; {link}</span>
                        </>
                      )}
                    </div>
                  </td>
                  <td className={`bridge-cl-amt${t.dir === "in" ? " in" : ""}`}>
                    {t.dir === "in" ? "+" : "−"}
                    {fmtUSD(t.amount)}
                  </td>
                  <td>
                    <div
                      className={`bridge-cl-catsel${openMenu === i ? " open" : ""}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        setOpenMenu((m) => (m === i ? null : i));
                      }}
                    >
                      {r.category ? (
                        <>
                          <span
                            className="bridge-cl-dot"
                            style={{ background: categoryColor(r.category) }}
                          />
                          {r.category}
                        </>
                      ) : (
                        <span className="bridge-cl-catsel-placeholder">Choose category</span>
                      )}
                      <span className="bridge-cl-chev">&#9662;</span>
                      {openMenu === i && (
                        <div className="bridge-cl-catmenu">
                          {CLASSIFY_CATEGORIES.map((c) => (
                            <div
                              key={c.name}
                              className="bridge-cl-catmenu-item"
                              onClick={(e) => {
                                e.stopPropagation();
                                setCategory(i, c.name);
                                setOpenMenu(null);
                              }}
                            >
                              <span className="bridge-cl-dot" style={{ background: c.color }} />
                              {c.name}
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                    {canRule &&
                      (r.ruled ? (
                        <button className="bridge-cl-rule made" type="button">
                          &#10003; Rule saved
                        </button>
                      ) : (
                        <button
                          className="bridge-cl-rule"
                          type="button"
                          onClick={() => setRule(i)}
                        >
                          + Always {t.merchant} &rarr; {r.category}
                        </button>
                      ))}
                  </td>
                  <td>
                    <div className="bridge-cl-status">
                      <span className={`bridge-cl-statdot ${statusTone}`} />
                      <span className={`bridge-cl-flag ${statusTone}`}>{flagLabel}</span>
                      <span className={`bridge-cl-receipt ${receipt}`}>
                        {receipt === "attached" && (
                          <svg viewBox="0 0 24 24">
                            <path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" />
                          </svg>
                        )}
                        {receiptLabel(receipt)}
                      </span>
                      <span className="bridge-cl-conf">
                        {t.pct > 0 ? `${t.pct}% confident` : "needs you"}
                      </span>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>

        {/* Bulk bar — pinned under the table */}
        <div className="bridge-cl-bulk">
          <span className="bridge-cl-bulk-l">
            <b>{read.selectedCount}</b> selected
          </span>
          <button
            className="bridge-cl-bulk-btn"
            type="button"
            onClick={bulkAccept}
            disabled={categorizedCount === 0 || allCheckable}
          >
            Accept Magellan&rsquo;s categories for selected
          </button>
        </div>
      </div>

      {/* What this updates — live consequence read */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this updates
          <span className="bridge-ni-outcome-prov firm">Computed from the transactions</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">This batch</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Classified</span>
              <span className={`v${read.needCatCount === 0 ? " good" : ""}`}>
                {read.classifiedCount} of {read.total}
              </span>
              <span className="kk">
                {read.needCatCount === 0
                  ? "all categorized"
                  : `${read.needCatCount} still need a category`}
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Selected to post</span>
              <span className="v">{read.selectedCount}</span>
              <span className="kk">{fmtUSD(read.selectedTotal)} of checked rows</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Largest bucket</span>
              <span className="v">{read.largest}</span>
              <span className="kk">{read.bucketCount} categories this batch</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Affects this period&rsquo;s P&amp;L</span>
              <span className="v">yes</span>
              <span className="kk">flows to cost categories</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Signal</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">New recurring spotted</span>
              <span className="v">1</span>
              <span className="kk">&ldquo;Notion&rdquo; &mdash; monthly</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Cost spike flagged</span>
              <span className="v alert">Marketing +38%</span>
              <span className="kk">vs last month</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">VAT-applicable</span>
              <span className="v">4 of {read.total}</span>
              <span className="kk">input VAT to reclaim</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Rules created</span>
              <span className={`v${read.rulesCreated > 0 ? " good" : ""}`}>
                {read.rulesCreated}
              </span>
              <span className="kk">fewer to review next time</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          Classifying assigns each transaction to a cost category &mdash; this is what makes the <b>P&amp;L, Cost Categories and CM1</b> real rather than estimated. Magellan proposes from the merchant, amount and history; you only touch the ones it&rsquo;s unsure about. A charge that looks recurring is flagged to set up as a <b>Recurring Cost</b>, and VAT-applicable lines are tagged so input VAT is reclaimable.
        </div>
      </div>

      {/* Commit */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the classifications &mdash; <b>nothing posts</b> to your P&amp;L until you confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Save for later
          </button>
          <button
            className={`bridge-ni-create${committed ? " done" : ""}`}
            type="button"
            onClick={commit}
            disabled={committed || read.selectedCount === 0}
          >
            {committed
              ? "✓ Transactions classified"
              : `Classify ${read.selectedCount} transaction${read.selectedCount === 1 ? "" : "s"} →`}
          </button>
        </div>
      </div>
    </div>
  );
}
