/** Direction of money flow. `in` = revenue / inflow, `out` = cost / outflow. */
export type TxDirection = "in" | "out";

/** Magellan's confidence band for a row's proposed category. */
export type TxConfidence = "ok" | "review";

/** Where the receipt for a row currently stands. */
export type ReceiptState = "attached" | "auto" | "missing";

/** A cost / revenue category Magellan can assign a transaction to. */
export interface CategoryOption {
  name: string;
  /** Dot color for the per-row selector + menu items. */
  color: string;
}

/** One transaction in the batch awaiting classification. */
export interface ClassifyTransaction {
  /** Primary description, e.g. "WooCommerce order #4821". */
  desc: string;
  /** Source / reference sub-line, e.g. "ch_3R8x · Stripe". */
  source: string;
  /** Absolute amount in USD (sign is derived from `dir`). */
  amount: number;
  dir: TxDirection;
  /** Magellan's proposed category name (empty string = none proposed). */
  category: string;
  /** Confidence band — drives the status dot + pre-checked state. */
  conf: TxConfidence;
  /** Confidence percentage (0 = needs the operator). */
  pct: number;
  /** Merchant key — used for the "+ Always merchant → category" rule. */
  merchant: string;
}

