/** Lookup helper: dot color for a category name (falls back to neutral). */
export function categoryColor(name: string): string {
  return CLASSIFY_CATEGORIES.find((c) => c.name === name)?.color ?? "#8a8d94";
}

/**
 * Receipt custody state for a row, derived from its source string + whether a
 * category has been set — mirrors the template's rec() logic:
 * - source carries "Receipt" → attached
 * - platform-sourced (Stripe / PayPal) → auto
 * - otherwise attached once categorized, missing while unclassified
 */
export function receiptState(t: ClassifyTransaction): ReceiptState {
  if (t.source.includes("Receipt")) return "attached";
  if (t.source.includes("Stripe") || t.source.includes("PayPal")) return "auto";
  return t.category ? "attached" : "missing";
}
